app = Flask(__name__)


@app.before_request
def security_middleware():
    """
    Middleware that:
    1. Authenticates the user via Bearer token
    2. Validates query depth and length
    3. Blocks introspection in production
    """
    # Only process GraphQL endpoint
    if request.path != "/graphql":
        return

    # --- Authentication ---
    current_user = None
    auth_header = request.headers.get("Authorization", "")
    if auth_header.startswith("Bearer "):
        token = auth_header[7:]
        # Limit token length to prevent abuse
        if len(token) <= 256:
            current_user = validate_token(token)
            if current_user is None:
                logger.info("Invalid token presented from %s", request.remote_addr)

    # Store in flask g-like mechanism via request environ
    request.environ["graphql_current_user"] = current_user

    # --- Query Validation (only for POST with JSON body) ---
    if request.method == "POST" and request.is_json:
        data = request.get_json(silent=True)
        if data is None:
            return jsonify({"errors": [{"message": "Invalid JSON body"}]}), 400

        query_str = data.get("query", "")

        # Check query length
        if len(query_str) > MAX_QUERY_LENGTH:
            logger.warning(
                "Query too long (%d chars) from %s",
                len(query_str),
                request.remote_addr,
            )
            return jsonify({
                "errors": [{"message": "Query exceeds maximum allowed length"}]
            }), 400

        # Check query depth
        depth = calculate_query_depth(query_str)
        if depth > MAX_QUERY_DEPTH:
            logger.warning(
                "Query too deep (depth %d) from %s",
                depth,
                request.remote_addr,
            )
            return jsonify({
                "errors": [{"message": f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}"}]
            }), 400

        # Block introspection in production
        if not INTROSPECTION_ALLOWED and contains_introspection(query_str):
            logger.warning("Introspection query blocked from %s", request.remote_addr)
            return jsonify({
                "errors": [{"message": "Introspection is not allowed"}]
            }), 400


@app.route("/graphql", methods=["GET"])
def graphql_playground():
    """Serve GraphQL Playground for development."""
    if os.environ.get("FLASK_ENV") == "production":
        return jsonify({"error": "Not available"}), 404
    return PLAYGROUND_HTML, 200


@app.route("/graphql", methods=["POST"])
def graphql_server():
    """Handle GraphQL queries."""
    data = request.get_json()

    # Build context with authenticated user
    context = {
        "current_user": request.environ.get("graphql_current_user"),
        "request": request,
    }

    success, result = graphql_sync(
        schema,
        data,
        context_value=context,
        debug=os.environ.get("FLASK_ENV") != "production",
    )

    status_code = 200 if success else 400

    # Scrub internal error details in production
    if os.environ.get("FLASK_ENV") == "production" and not success:
        if "errors" in result:
            result["errors"] = [
                {"message": "An error occurred processing your request"}
                for _ in result["errors"]
            ]

    return jsonify(result), status_code


